#!/usr/bin/env bash
#
# Generate all protobuf bindings.
# Run from repository root.
set -e
set -u

if ! [[ "$0" =~ "scripts/genproto.sh" ]]; then
	echo "must be run from repository root"
	exit 255
fi

pushd "internal/tools"
INSTALL_PKGS="github.com/daixiang0/gci github.com/grafana/wiresmith/cmd/wiresmith"
for pkg in ${INSTALL_PKGS}; do
	GO111MODULE=on go install "$pkg"
done
popd

# All protos are generated by the wiresmith compiler, as repo-root-relative paths
# (wiresmith resolves positional file args against the current directory, not
# --proto_path). They live under prompb/, the buf module root; the wiresmith pass
# below runs with -proto_path=prompb so their import keys and descriptor paths are
# prompb-relative, matching both buf and upstream's registration. The on-wire
# format is byte-identical to the former gogo output; only the generated Go
# shape/methods change.
WIRESMITH_PROTOS="prompb/types.proto prompb/remote.proto prompb/io/prometheus/write/v2/types.proto prompb/io/prometheus/client/metrics.proto"

echo "generating code"

# wiresmith pass: rooted at prompb/ (same root as buf) so proto import strings
# like "types.proto" resolve identically for both tools and generated descriptor
# paths stay prompb-relative, matching upstream gogo's proto registration. Emits
# source-relative <name>.pb.go + <name>_compare.pb.go + <name>_util.pb.go siblings.
# The google.protobuf.Timestamp fields in metrics.proto resolve via protocompile's
# standard imports and are substituted for time.Time by the stdtime option.
wiresmith -proto_path=prompb -out=prompb -module=github.com/prometheus/prometheus ${WIRESMITH_PROTOS}
gci write -s standard -s default -s "prefix(github.com/prometheus/prometheus)" prompb/*.pb.go prompb/io/prometheus/write/v2/*.pb.go prompb/io/prometheus/client/*.pb.go
